  ('cpa-moex-01237', 'cpa', 'cpa-moex-104-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '大順公司實施品質檢驗程序，若生產流程不當將發生$28,000的損失，若想要避免生產流程不當再發 生，須投入$4,000進行原因調查，找到原因後需投入$12,000進行改正。請問當生產流程不當的機率 大於多少，即值得大順公司進行調查及改正行動？', '["20%", "25%", "30%", "35%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "3bf055ad8f6f", "answer_pdf_sha1": "e8f11787a170", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
